func validateOrderRequest(req *OrderRequest) error {
	if req == nil { return ErrNull }
	if len(req.Items) == 0 { return ErrEmpty }
	return nil
}

func calculateOrderTotal(items []OrderItem) float64 {
	total := 0.0
	for _, item := range items {
		total += item.Price * float64(item.Qty)
	}
	return total
}

func ProcessOrder(ctx context.Context, req *OrderRequest) error {
	if err := validateOrderRequest(req); err != nil { return err }
	customer, err := db.FindCustomer(ctx, req.CustomerID)
	if err != nil { return err }
	order := &Order{Customer: customer, Total: calculateOrderTotal(req.Items)}
	if err := db.SaveOrder(ctx, order); err != nil { return err }
	notifier.Notify(ctx, order)
	return nil
}
